// ── SWARM COORDINATOR: Task Classifier ──────────────────────────────
// Inspired by Ruflo's 3-tier routing model.
// Routes tasks to the right specialist agent based on complexity + intent.

const body = $input.first().json.body || $input.first().json;
const task = (body.task || body.message || body.prompt || '').trim();
const forceAgent = body.agent || null; // allow manual override

if (!task) {
  throw new Error('No task provided. Send: { "task": "your request here" }');
}

// ── Complexity Classification ─────────────────────────────────────────
// Tier 1 (tiny): lookups, formatting, yes/no, quick answers
// Tier 2 (medium): summaries, explanations, short code, analysis
// Tier 3 (heavy): architecture, multi-step plans, long code, research

const words = task.split(/\s+/).length;
const heavyKeywords = ['architect', 'design', 'build', 'implement', 'refactor',
  'multi-step', 'plan', 'research', 'analyze', 'investigate', 'comprehensive',
  'full', 'complete', 'system', 'create app', 'write app', 'debug'];
const codeKeywords = ['code', 'function', 'script', 'bug', 'error', 'fix',
  'write', 'implement', 'build', 'deploy', 'docker', 'python', 'javascript',
  'bash', 'sql', 'api', 'endpoint', 'class', 'module', 'test'];
const searchKeywords = ['search', 'find', 'look up', 'what is', 'who is',
  'latest', 'news', 'current', 'today', 'web', 'internet', 'google'];

const taskLower = task.toLowerCase();

let complexity = 'medium';
if (words > 60 || heavyKeywords.some(k => taskLower.includes(k))) {
  complexity = 'heavy';
} else if (words < 15) {
  complexity = 'tiny';
}

// ── Agent Routing ─────────────────────────────────────────────────────
let agent = 'openwebui'; // default fallback
let agentUrl = 'http://open-webui:3000';
let agentEndpoint = '/api/chat/completions';
let model = 'qwen2.5:7b';

if (forceAgent) {
  agent = forceAgent;
}

if (agent === 'auto' || !forceAgent) {
  if (searchKeywords.some(k => taskLower.includes(k))) {
    agent = 'perplexica';
    agentUrl = 'http://perplexica:3002';
    agentEndpoint = '/api/search';
    model = 'search';
  } else if (codeKeywords.some(k => taskLower.includes(k)) || complexity === 'heavy') {
    agent = 'openhands';
    agentUrl = 'http://openhands:3003';
    agentEndpoint = '/api/conversations';
    model = process.env.OPENHANDS_MODEL || 'ollama/qwen2.5-coder:14b';
  } else {
    agent = 'litellm';
    agentUrl = 'http://litellm:4000';
    agentEndpoint = '/v1/chat/completions';
    // Complexity-based model selection (Ruflo 3-tier pattern)
    if (complexity === 'heavy') {
      model = process.env.PERPLEXICA_CHAT_MODEL || 'llama3.3:70b';
    } else if (complexity === 'medium') {
      model = 'qwen2.5:32b';
    } else {
      model = 'qwen2.5:7b';
    }
  }
}

const taskId = `swarm_${Date.now()}_${Math.random().toString(36).substr(2,6)}`;

return {
  task,
  taskId,
  complexity,
  agent,
  agentUrl,
  agentEndpoint,
  model,
  timestamp: new Date().toISOString(),
  words
};

// Normalize responses from all 3 agents into a standard shape
const routerData = $('Classify & Route Task').first().json;
const raw = $input.first().json;

let result = '';

// Perplexica response
if (routerData.agent === 'perplexica') {
  result = raw.message || raw.answer || raw.text || JSON.stringify(raw);
}
// OpenHands response
else if (routerData.agent === 'openhands') {
  result = raw.conversation_id
    ? `OpenHands task started. Conversation ID: ${raw.conversation_id}. Check http://localhost:3003`
    : raw.message || JSON.stringify(raw);
}
// LiteLLM / OpenAI-compatible response
else {
  result = raw.choices?.[0]?.message?.content
    || raw.content
    || raw.message
    || JSON.stringify(raw);
}

return {
  taskId: routerData.taskId,
  task: routerData.task,
  agent: routerData.agent,
  model: routerData.model,
  complexity: routerData.complexity,
  result,
  timestamp: routerData.timestamp,
  completed_at: new Date().toISOString()
};
